import{_ as r,C as i,o as l,c as d,j as o,a,E as n,a7 as s}from"./chunks/framework.C4ZIv4ii.js";const x=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1781971351000}'),c={name:"changelog.md"},h={id:"v1-3-30",tabindex:"-1"};function g(u,e,m,p,f,b){const t=i("Badge");return l(),d("div",null,[e[3]||(e[3]=o("h1",{id:"changelog",tabindex:"-1"},[a("Changelog "),o("a",{class:"header-anchor",href:"#changelog","aria-label":'Permalink to "Changelog"'},"​")],-1)),e[4]||(e[4]=o("p",null,[a("All notable changes to "),o("strong",null,"FalconCMS"),a(" are documented here."),o("br"),a(" Format follows "),o("a",{href:"https://keepachangelog.com/en/1.0.0/",target:"_blank",rel:"noreferrer"},"Keep a Changelog"),a(" — versions are sorted newest first.")],-1)),e[5]||(e[5]=o("hr",null,null,-1)),o("h2",h,[e[0]||(e[0]=a("v1.3.30 ",-1)),n(t,{type:"tip",text:"Latest"}),e[1]||(e[1]=a()),e[2]||(e[2]=o("a",{class:"header-anchor",href:"#v1-3-30","aria-label":'Permalink to "v1.3.30 <Badge type="tip" text="Latest" /> {#v1-3-30}"'},"​",-1))]),e[6]||(e[6]=s('<p><strong>Released: 2026-06-20</strong></p><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Settings — Demo mode</strong> — <code>register_url</code> and <code>login_url</code> inputs now properly disabled with a visible warning banner; initial attempt in v1.3.29 was incomplete</li></ul><hr><h2 id="v1-3-29" tabindex="-1">v1.3.29 <a class="header-anchor" href="#v1-3-29" aria-label="Permalink to &quot;v1.3.29 {#v1-3-29}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Settings — Demo mode</strong> — Initial attempt to disable registration URL and login URL fields when <code>APP_DEMO=true</code> (superseded by v1.3.30)</li></ul><hr><h2 id="v1-3-28" tabindex="-1">v1.3.28 <a class="header-anchor" href="#v1-3-28" aria-label="Permalink to &quot;v1.3.28 {#v1-3-28}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Demo credentials</strong> — Corrected email to <code>admin@falconcms.demo</code> and password to <code>FalconDemo2025!</code> (were set to wrong values in v1.3.26)</li></ul><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Docs — Demo page</strong> — Live demo request page (<code>/demo</code>) with lead capture form; credentials sent to visitor&#39;s email via EmailJS after form submission</li></ul><hr><h2 id="v1-3-27" tabindex="-1">v1.3.27 <a class="header-anchor" href="#v1-3-27" aria-label="Permalink to &quot;v1.3.27 {#v1-3-27}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Demo credentials box</strong> — Applied to the correct login view (<code>login-modern.blade.php</code>); previous version edited the wrong file (<code>login.blade.php</code>)</li></ul><hr><h2 id="v1-3-26" tabindex="-1">v1.3.26 <a class="header-anchor" href="#v1-3-26" aria-label="Permalink to &quot;v1.3.26 {#v1-3-26}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Demo mode — Login page</strong> — Demo credentials box displayed above login form when <code>APP_DEMO=true</code></li><li><strong>Demo mode — User management</strong> — All fields on user create and user edit pages disabled with warning banner when <code>APP_DEMO=true</code>; submit button also disabled</li></ul><hr><h2 id="v1-3-25" tabindex="-1">v1.3.25 <a class="header-anchor" href="#v1-3-25" aria-label="Permalink to &quot;v1.3.25 {#v1-3-25}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — <code>theme_footer_logo</code> and <code>theme_site_logo</code> rows deleted from <code>cms_settings</code> during <code>falcon:update</code> so the embedded base64 default logo is always used and never overridden by a stale DB value</li></ul><hr><h2 id="v1-3-24" tabindex="-1">v1.3.24 <a class="header-anchor" href="#v1-3-24" aria-label="Permalink to &quot;v1.3.24 {#v1-3-24}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Default logo embedded as base64 directly in the footer template; eliminates dependency on file copy or asset publish step during deployment</li></ul><hr><h2 id="v1-3-23" tabindex="-1">v1.3.23 <a class="header-anchor" href="#v1-3-23" aria-label="Permalink to &quot;v1.3.23 {#v1-3-23}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Logo element moved outside the widget check block so it always renders in column 1 regardless of whether any widgets are active</li></ul><hr><h2 id="v1-3-22" tabindex="-1">v1.3.22 <a class="header-anchor" href="#v1-3-22" aria-label="Permalink to &quot;v1.3.22 {#v1-3-22}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — <code>syncFooterDefaults()</code> now copies the logo file directly, independent of <code>vendor:publish</code></li></ul><hr><h2 id="v1-3-21" tabindex="-1">v1.3.21 <a class="header-anchor" href="#v1-3-21" aria-label="Permalink to &quot;v1.3.21 {#v1-3-21}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Removed <code>theme_site_logo</code> fallback from footer logo; <code>syncFooterDefaults()</code> called during <code>falcon:update</code> to ensure footer defaults are always set</li></ul><hr><h2 id="v1-3-20" tabindex="-1">v1.3.20 <a class="header-anchor" href="#v1-3-20" aria-label="Permalink to &quot;v1.3.20 {#v1-3-20}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Fixed white/invisible logo by using the correct asset; updated default About text and copyright text; migration added to correct existing DB values</li></ul><hr><h2 id="v1-3-19" tabindex="-1">v1.3.19 <a class="header-anchor" href="#v1-3-19" aria-label="Permalink to &quot;v1.3.19 {#v1-3-19}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-9" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-9" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong><code>falcon:update</code></strong> — Published admin views are now deleted on update instead of being re-published, ensuring the package&#39;s vendor views are always served fresh</li></ul><hr><h2 id="v1-3-18" tabindex="-1">v1.3.18 <a class="header-anchor" href="#v1-3-18" aria-label="Permalink to &quot;v1.3.18 {#v1-3-18}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Customizer — Performance</strong> — &quot;Clear All Cache&quot; button added to Performance section for one-click cache clearing from the admin</li></ul><hr><h2 id="v1-3-17" tabindex="-1">v1.3.17 <a class="header-anchor" href="#v1-3-17" aria-label="Permalink to &quot;v1.3.17 {#v1-3-17}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-10" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-10" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer</strong> — Logo removed from the lower footer bar; logo now only appears in the top footer column 1 widget area</li></ul><hr><h2 id="v1-3-16" tabindex="-1">v1.3.16 <a class="header-anchor" href="#v1-3-16" aria-label="Permalink to &quot;v1.3.16 {#v1-3-16}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-11" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-11" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Replaced with the correct <code>falcon-cms-footer-logo</code> asset; size increased to <code>h-12</code> for better visibility</li></ul><hr><h2 id="v1-3-15" tabindex="-1">v1.3.15 <a class="header-anchor" href="#v1-3-15" aria-label="Permalink to &quot;v1.3.15 {#v1-3-15}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Footer</strong> — FalconCMS logo added to the footer bottom bar; default copyright text updated</li></ul><hr><h2 id="v1-3-14" tabindex="-1">v1.3.14 <a class="header-anchor" href="#v1-3-14" aria-label="Permalink to &quot;v1.3.14 {#v1-3-14}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-12" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-12" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Product editor</strong> — Added <code>x-cloak</code> to the product data metabox to prevent Alpine.js flash of unstyled content (FOUC) on page load</li></ul><hr><h2 id="v1-3-13" tabindex="-1">v1.3.13 <a class="header-anchor" href="#v1-3-13" aria-label="Permalink to &quot;v1.3.13 {#v1-3-13}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-13" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-13" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong><code>falcon:update</code></strong> — Admin views are now automatically re-published during update to keep the published copies in sync with the package</li></ul><hr><h2 id="v1-3-12" tabindex="-1">v1.3.12 <a class="header-anchor" href="#v1-3-12" aria-label="Permalink to &quot;v1.3.12 {#v1-3-12}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-14" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-14" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Sale end date</strong> — <code>sale_ends_at</code> datetime input minimum value now set using client-side local time instead of server UTC, preventing timezone-related validation errors</li></ul><hr><h2 id="v1-3-11" tabindex="-1">v1.3.11 <a class="header-anchor" href="#v1-3-11" aria-label="Permalink to &quot;v1.3.11 {#v1-3-11}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-15" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-15" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Product archive</strong> — <code>archive-product.blade.php</code> now uses <code>productCategories</code> relation instead of the old <code>taxonomyTerms</code> call</li><li><strong>Product archive</strong> — <code>productCategories</code> relation eagerly loaded on CPT archive queries (e.g. <code>/product/</code>) to prevent N+1 queries</li></ul><hr><h2 id="v1-3-10" tabindex="-1">v1.3.10 <a class="header-anchor" href="#v1-3-10" aria-label="Permalink to &quot;v1.3.10 {#v1-3-10}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="fixed-16" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-16" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Sale end date validation</strong> — Removed <code>after:now</code> rule that was incorrectly rejecting valid future dates in some timezone configurations</li></ul><hr><h2 id="v1-3-9" tabindex="-1">v1.3.9 <a class="header-anchor" href="#v1-3-9" aria-label="Permalink to &quot;v1.3.9 {#v1-3-9}&quot;">​</a></h2><p><strong>Released: 2026-06-19</strong></p><h3 id="fixed-17" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-17" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>PHP_BINARY</strong> — Resolved to the CLI <code>php</code> binary in web (php-fpm) context where <code>PHP_BINARY</code> points to the FPM worker</li><li><strong>Product categories</strong> — Category label display corrected on product cards and single product pages</li><li><strong>Sale end date</strong> — Validation and countdown timer logic corrected</li><li><strong>Page Builder</strong> — Fixed offset constants in <code>parseColumnsFromContent()</code> that caused incorrect column parsing</li><li><strong>Shop</strong> — Tab active-state bug fixed; <code>hold_stock</code> order cancellation implemented</li><li><strong>Hooks &amp; helpers</strong> — Remaining <code>lazy_</code> CSS classes and helper function references renamed to <code>falcon_</code> throughout the package theme source</li></ul><hr><h2 id="v1-3-4" tabindex="-1">v1.3.4 <a class="header-anchor" href="#v1-3-4" aria-label="Permalink to &quot;v1.3.4 {#v1-3-4}&quot;">​</a></h2><p><strong>Released: 2026-06-16</strong></p><h3 id="fixed-18" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-18" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Theme system</strong> — Themes now resolve exclusively from the app&#39;s <code>resources/views/themes/</code> directory; vendor path no longer used as a runtime fallback</li><li><strong>Page Builder shortcodes</strong> — All remaining <code>[lazy_*]</code> element outputs converted to <code>[falcon_*]</code> (<code>text_block</code>, <code>special_text</code>, <code>html</code>, <code>icon_box</code>, <code>acc_item</code>, <code>tab_item</code>, <code>icon_list_item</code>); <code>parseColumn()</code> now reads both legacy <code>[lazy_*]</code> and new <code>[falcon_*]</code> element shortcodes; <code>unwrapEditorMarkup()</code> handles <code>falcon_</code> tags; sub-element closing tag patterns accept both prefixes for backward compatibility</li><li><strong>Child theme activation</strong> — Fixed <code>theme.json</code> parent reference (<code>lazy-theme</code> → <code>falcon-theme</code>); added required <code>index.blade.php</code> to child theme</li><li><strong>Header / Footer logo</strong> — Default FalconCMS logo shown when no custom logo is configured; logo served from published asset path <code>vendor/falcon-cms/images/falcon-cms-logo.png</code></li></ul><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong><code>falcon:install</code> screenshot publishing</strong> — Theme screenshots are automatically copied to <code>public/themes/{slug}/</code> so they appear in the Themes panel immediately after installation</li><li><strong><code>theme.json</code> for Falcon Theme</strong> — Adds proper metadata (name, version, description, author)</li><li><strong>New theme screenshots</strong> — Updated preview images for <code>falcon-theme</code> and <code>falcon-theme-child</code></li><li><strong>Default logo asset</strong> — <code>public/assets/images/falcon-cms-logo.png</code> included in the package and published with <code>falcon-cms-assets</code></li></ul><hr><h2 id="v1-3-3" tabindex="-1">v1.3.3 <a class="header-anchor" href="#v1-3-3" aria-label="Permalink to &quot;v1.3.3 {#v1-3-3}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><h3 id="fixed-19" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-19" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Dashboard update check</strong> — <code>version.json</code> bumped to <code>1.3.2</code>; LAZY_CMS_VERSION constant now reflects the installed Packagist version correctly</li></ul><hr><h2 id="v1-3-2" tabindex="-1">v1.3.2 <a class="header-anchor" href="#v1-3-2" aria-label="Permalink to &quot;v1.3.2 {#v1-3-2}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><h3 id="fixed-20" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-20" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Default <code>login_url</code> value changed from <code>admin-login</code> to <code>falcon-admin</code> in both the install command and the migration seeder</li></ul><hr><h2 id="v1-3-1" tabindex="-1">v1.3.1 <a class="header-anchor" href="#v1-3-1" aria-label="Permalink to &quot;v1.3.1 {#v1-3-1}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><h3 id="fixed-21" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-21" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Default <code>register_url</code> value corrected to <code>falcon-registration</code> in the install command</li></ul><hr><h2 id="v1-3-0" tabindex="-1">v1.3.0 <a class="header-anchor" href="#v1-3-0" aria-label="Permalink to &quot;v1.3.0 {#v1-3-0}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Complete rebrand from <strong>FalconCMS</strong> to <strong>FalconCMS</strong> — namespaces, command names (<code>falcon:install</code>), config keys, view namespaces, and all public-facing strings updated</li></ul><hr><h2 id="v1-0-0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1-0-0" aria-label="Permalink to &quot;v1.0.0 {#v1-0-0}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><p>Initial public release of <strong>FalconCMS</strong> — a powerful Laravel CMS package with page builder, e-commerce, and a WordPress-like admin dashboard.</p><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><strong>WordPress-like Admin Dashboard</strong> — Sidebar navigation, top bar, role-based permissions, activity logs</li><li><strong>Page Builder (Falcon Builder)</strong> — Drag-and-drop visual editor with rows, columns, and element blocks</li><li><strong>Post &amp; Page Management</strong> — Custom post types, categories, tags, featured images, SEO fields</li><li><strong>Media Library</strong> — Upload, manage, and select images/files across the admin</li><li><strong>User &amp; Role Management</strong> — Granular permission system with custom roles</li><li><strong>Multi-language Support</strong> — Built-in language management</li><li><strong>Theme System</strong> — Installable themes with Customizer support (header, footer, colors, typography)</li><li><strong>Hook Architecture</strong> — WordPress-style <code>add_lazy_action</code> / <code>add_lazy_filter</code> for extensibility</li><li><strong>Custom Options Pages</strong> — Register custom settings pages via config</li></ul><h3 id="e-commerce-shop" tabindex="-1">E-Commerce (Shop) <a class="header-anchor" href="#e-commerce-shop" aria-label="Permalink to &quot;E-Commerce (Shop)&quot;">​</a></h3><ul><li><strong>Product Management</strong> — Simple and variable products, SKU, stock, sale price with scheduled expiry (<code>sale_ends_at</code>)</li><li><strong>Digital / Downloadable Products</strong> — Attach files from the media library; secure token-based download links with expiry and download count limits</li><li><strong>Orders</strong> — Full order lifecycle (pending → processing → shipped → completed), order notes, status history</li><li><strong>Cart &amp; Checkout</strong> — AJAX cart, coupon codes, shipping zones, tax rules</li><li><strong>Payments</strong> — Cash on Delivery, Stripe, SSLCommerz integrations</li><li><strong>Customer Account</strong> — Order history, downloads tab, address management</li><li><strong>Sales Reports</strong> — Revenue by period (daily/weekly/monthly), top products, customer LTV, CSV export</li><li><strong>Shop Settings</strong> — Currency, inventory, email notifications, shipping, tax, coupon management</li></ul><h3 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">​</a></h3><ul><li><strong>URL-aware Settings Tabs</strong> — Tab switches update the browser URL via <code>history.replaceState</code></li><li><strong>Sidebar Collapse</strong> — &quot;Collapse Menu&quot; button; icon-only mode persisted in <code>localStorage</code> with no flash on navigation</li><li><strong>FalconCMS Branding</strong> — FCM logo in admin top bar</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>HTTP Security Headers</strong> — <code>X-Content-Type-Options</code>, <code>X-Frame-Options</code>, <code>Referrer-Policy</code>, <code>Permissions-Policy</code>, CSP, HSTS</li><li><strong>Rate Limiting</strong> — Login, forgot-password, comments, cart operations, file downloads</li><li><strong>CSRF Protection</strong> — All state-changing routes protected</li><li><strong>Input Validation</strong> — Cart quantities, file uploads, comment length, user enumeration prevention</li><li><strong>Secure Downloads</strong> — Token-based file delivery; tokens expire and have per-user download limits</li></ul><h3 id="developer-tools" tabindex="-1">Developer Tools <a class="header-anchor" href="#developer-tools" aria-label="Permalink to &quot;Developer Tools&quot;">​</a></h3><ul><li><strong>Artisan Commands</strong> — <code>lazy:expire-sales</code> (scheduled sale price cleanup)</li><li><strong>REST API</strong> — Configurable API key authentication</li><li><strong>Backup &amp; Snapshots</strong> — Database and file backup tools</li><li><strong>WordPress Import</strong> — Import posts from a WordPress XML export</li><li><strong>Analytics Dashboard</strong> — Basic traffic and content stats</li><li><strong>Maintenance Mode</strong> — Toggle from Customizer with custom message and countdown timer</li></ul>',151))])}const q=r(c,[["render",g]]);export{x as __pageData,q as default};
